// ============================================================
// Extract NodeId - compatible toutes versions node-red-contrib-opcua
// ============================================================
var nodeIdStr = null;

// Format 1: msg.topic = "ns=3;i=1117"  (versions récentes subscribe)
if (msg.topic && typeof msg.topic === 'string' && msg.topic.indexOf('i=') !== -1) {
    nodeIdStr = msg.topic;
}
// Format 2: msg.payload est un objet avec .nodeId
else if (msg.payload && typeof msg.payload === 'object' && msg.payload.nodeId) {
    var nid = msg.payload.nodeId;
    nodeIdStr = (typeof nid === 'object' && nid.value) ? String(nid.value) : String(nid);
}
// Format 3: msg.nodetype existe (certaines versions)
else if (msg.nodetype && msg.nodeId) {
    nodeIdStr = String(msg.nodeId);
}
// Format 4: msg.addressSpaceItems (mode read)
else if (msg.addressSpaceItems && msg.addressSpaceItems.length > 0) {
    var asi = msg.addressSpaceItems[0];
    nodeIdStr = asi.nodeId || asi.item || '';
}

// Extraire l'entier après i=
var m = nodeIdStr ? String(nodeIdStr).match(/i=(\d+)/) : null;
msg.nodeId = m ? parseInt(m[1]) : 0;

// Aplatir la valeur payload
if (msg.payload !== null && typeof msg.payload === 'object') {
    if (msg.payload.value !== undefined)       msg.payload = msg.payload.value;
    else if (msg.payload.Value !== undefined)  msg.payload = msg.payload.Value;
}

// Debug: log dans la console Node-RED si nodeId = 0
if (msg.nodeId === 0) {
    node.warn("NodeId non trouvé - topic: " + JSON.stringify(msg.topic) + 
              " | payload keys: " + JSON.stringify(Object.keys(msg.payload || {})) +
              " | payload sample: " + JSON.stringify(msg.payload).substring(0, 200));
}

return msg;

var v = msg.payload || 0;
context.set('P_1', v);
flow.set('P_1', v);
flow.set('P_EXTRACTION_1', v);
global.set('P_1', v);
global.set('P_EXTRACTION_1', v);
return msg;

var P  = flow.get('P_1') || 0;
var PF = flow.get('PF_1') || 0.9;
var S  = PF > 0 ? P / PF : 0;
var Q  = Math.sqrt(Math.max(0, S*S - P*P));
// Calcul énergie consommée (kWh) pour ce PM, dt=5s
var dt = 5 / 3600;
var kwh = (global.get('energy_kwh_PM1') || 0) + P * dt;
global.set('energy_kwh_PM1', kwh);
var out = {P: +P.toFixed(2), Q: +Q.toFixed(2), S: +S.toFixed(2)};
return [
  {payload: out.P, topic:'P'},
  {payload: out.Q, topic:'Q'},
  {payload: out.S, topic:'S'},
  {payload: +kwh.toFixed(3), topic:'Energy_kWh'}
];

